INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("アヤネ", 0.0, 2, 2, 10046, 102301, 24001, "2020/07/31 12:00:00", 401, 0.0, 24, "やったね、ぷうきち！\nこれならお兄ちゃんたちの\nお手本になれたよね！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("アヤネ", 0.0, 1, 2, 10046, 102301, 24002, "2020/07/31 12:00:00", 402, 2.21, 24, "私たちの勝ちだね！\nぷうきちと一緒なら\nどんなボールでも\nホームランを打ってみせるよ！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("アヤネ", 0.0, 2, 2, 10046, 102301, 24003, "2020/07/31 12:00:00", 403, 0.0, 24, "やったやったぁ！\nお兄ちゃん、見ててくれた？\n私、すっごくがんばったよ！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("アサヒ", 0.0, 2, 1, 10046, 192201, 24004, "2020/07/31 12:00:00", 701, 1.99, 24, "特訓の成果が出たみたいだ！\nもっと練習を重ねて\nこの調子で上達していこう！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("アサヒ", 0.0, 1, 2, 10046, 192201, 24005, "2020/07/31 12:00:00", 702, 2.21, 24, "よし、いい感じだ！\nキャプテンとしての仕事は\nきっちり果たせそうだよ", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("アサヒ", 0.0, 2, 1, 10046, 192201, 24006, "2020/07/31 12:00:00", 703, 3.33, 24, "試合に向けて\nいい感覚を掴めた気がするよ！\nこのまま一気に全国大会だ！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("部員３", 0.0, 2, 2, 10046, 192301, 24007, "2020/07/31 12:00:00", 801, 0.0, 24, "このくらい余裕だ\nオレたちは全国大会を\n目指してるんだからな", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("部員３", 0.0, 1, 2, 10046, 192301, 24008, "2020/07/31 12:00:00", 802, 2.68, 24, "オレだって\nビーチベースボール選手だ\nどんな球だろうが\n全部スタンドまで飛ばしてやる", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("部員３", 0.0, 2, 2, 10046, 192301, 24009, "2020/07/31 12:00:00", 803, 0.0, 24, "いい感じだ\nこれなら試合でも活躍できそうだ\n大暴れしてやる！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("", 0.0, 1, 1, 10046, 192501, 24010, "2020/07/31 12:00:00", 501, 0.0, 24, "やった！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("", 0.0, 1, 1, 10046, 192501, 24011, "2020/07/31 12:00:00", 502, 0.0, 24, "勝ったよ！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("", 0.0, 1, 1, 10046, 192501, 24012, "2020/07/31 12:00:00", 503, 0.0, 24, "いい調子！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ミサト", 0.0, 6, 2, 10046, 113501, 24013, "2020/07/31 12:00:00", 111, 5.33, 24, "あら～…もしかして\n勝っちゃったのかしら？\nみんなの練習を見ていたから\nかもしれないわね", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ミサト", 0.0, 1, 2, 10046, 113501, 24014, "2020/07/31 12:00:00", 112, 6.85, 24, "みんなの力になりたくて\n先生も頑張ってみました～！\nうまく投げられたみたいで\nよかったわ～！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ミサト", 0.0, 1, 2, 10046, 113501, 24015, "2020/07/31 12:00:00", 113, 3.0, 24, "練習お疲れさま～！\n先生も協力できて\nとってもうれしいわ～♪\n次も頑張りましょうね～！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ダイチ", 0.0, 1, 2, 10046, 192401, 24016, "2020/07/31 12:00:00", 611, 6.11, 24, "まだ練習が足りねえみてえだな\nこれっぽっちも本気で\n投げてねえっつーの\nもう一回やんぞ！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ダイチ", 0.0, 1, 2, 10046, 192401, 24017, "2020/07/31 12:00:00", 612, 6.75, 24, "ふん、当然の結果だな\n俺の球は、誰にも打てねえよ！\nまたやりてえっつーなら\nとことん付き合ってやるぜ！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ダイチ", 0.0, 2, 2, 10046, 192401, 24018, "2020/07/31 12:00:00", 613, 0.0, 24, "おっしゃあ！\nこの勢いで全国に行ってやるぜ！\n全員三振で仕留めてやる！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ハツネ", 0.0, 2, 1, 10046, 113401, 24019, "2020/07/31 12:00:00", 211, 4.52, 24, "きらーん☆\nハツネちゃんの大勝利なのだ～！\nみんながもっと上達できるように\n私もまだまだ頑張るからね！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ハツネ", 0.0, 2, 1, 10046, 113401, 24020, "2020/07/31 12:00:00", 212, 3.89, 24, "やったあ！　私の勝ちだね！\nチアリーダーもピッチャーも\nハツネちゃんに任せてよ！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ハツネ", 0.0, 1, 2, 10046, 113401, 24021, "2020/07/31 12:00:00", 213, 13.49, 24, "よお～し、この調子でもっと\n頑張ろう…と思ったけど\n超能力を使ったから…\n眠くなってきちゃった…すやぁ…", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("カヤ", 0.0, 1, 2, 10046, 106501, 24022, "2020/07/31 12:00:00", 311, 3.17, 24, "いい勝負だったぜ！\nたぎっちまって\nつい本気で投げちまったよ", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("カヤ", 0.0, 1, 2, 10046, 106501, 24023, "2020/07/31 12:00:00", 312, 4.42, 24, "どうだ？\nオレ様のボールは熱かっただろ！\nま、でもおまえらの根性も\nなかなかのもんだったぜ", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("カヤ", 0.0, 6, 1, 10046, 106501, 24024, "2020/07/31 12:00:00", 313, 2.89, 24, "なんだよ、そんなもんか？\nこっちはまだまだ投げたりねえ\nもっと勝負しようぜ！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("アヤネ", 0.0, 4, 3, 10046, 102301, 24025, "2020/07/31 12:00:00", 421, 3.71, 24, "あとちょっとだったのに～！\n次こそぷうきちと一緒に\n勝ってみせるからね！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("アサヒ", 0.0, 2, 1, 10046, 192201, 24026, "2020/07/31 12:00:00", 721, 5.1, 24, "いい勝負だったね！\nでも、やっぱり悔しいな…\nもっと練習して\n今度は絶対に俺が勝つから！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("部員３", 0.0, 1, 3, 10046, 192301, 24027, "2020/07/31 12:00:00", 821, 4.34, 24, "ちっ…あと一歩足りなかったか\n次こそは絶対に勝つから\nそのつもりでいろ", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("", 0.0, 1, 1, 10046, 192501, 24028, "2020/07/31 12:00:00", 521, 0.0, 24, "いい勝負だったよ\nまたやろうね", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ミサト", -360.0, 1, 2, 10046, 113501, 24029, "2020/07/31 12:00:00", 101, 5.62, 24, "とってもよくできました～♪\n頑張ってくれて先生うれしいわ\nこれからも試合に向けて\n練習していきましょうね～", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ミサト", -360.0, 1, 2, 10046, 113501, 24030, "2020/07/31 12:00:00", 102, 9.58, 24, "頑張った成果ね～！\nこのまま練習を続ければ\nもっとすごい成績を残せそうよ\n期待してますからね～！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ミサト", -360.0, 2, 2, 10046, 113501, 24031, "2020/07/31 12:00:00", 103, 0.0, 24, "いい子、いい子～♪\n頑張り屋さんのあなたを\nたっくさん褒めてあげますからね", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ミサト", -360.0, 2, 1, 10046, 113501, 24032, "2020/07/31 12:00:00", 104, 9.13, 24, "夢に向けて、一歩前進できたわね\nこの調子で、夢を叶えましょう\n目指せ、全国大会～！", 0.0, "2030/12/17 14:59:59");
INSERT INTO `v1_f19e1b2cb05ff78cee95de4f3ef94fc0488911293dd9d71586f83eb7343b12a4` VALUES ("ミサト", -360.0, 1, 2, 10046, 113501, 24033, "2020/07/31 12:00:00", 105, 8.27, 24, "絶好調ね～♪\nきっと試合でも大活躍\n間違いなしだわ\n楽しみにしていますからね～！", 0.0, "2030/12/17 14:59:59");
